unit lipdecide;

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

function REALCOMPARE(A, B: real): COMPTYPE;
var
  diff: real;
  scaledA, scaledB, scaledDiff: real;
begin
  scaledA := A * 1000000.0;
  scaledB := B * 1000000.0;
  scaledDiff := scaledA - scaledB;

  if scaledDiff < 0.0 then
    REALCOMPARE := LT
  else if scaledDiff > 0.0 then
    REALCOMPARE := GT
  else
    REALCOMPARE := EQ;
end;

function distance(i, j: integer): real;
begin
  distance := sqrt(sqr(X[i] - X[j]) + sqr(Y[i] - Y[j]));
end;

function angle(i, j, k: integer): real;
var
  vec1x, vec1y, vec2x, vec2y, dot, mag1, mag2: real;
begin
  vec1x := X[i] - X[j];
  vec1y := Y[i] - Y[j];
  vec2x := X[k] - X[j];
  vec2y := Y[k] - Y[j];

  dot := vec1x * vec2x + vec1y * vec2y;
  mag1 := sqrt(sqr(vec1x) + sqr(vec1y));
  mag2 := sqrt(sqr(vec2x) + sqr(vec2y));

  if (mag1 < 1.0e-10) or (mag2 < 1.0e-10) then
    angle := -1.0
  else
  begin
    angle := arctan2(abs(vec1x * vec2y - vec1y * vec2x), dot);
    if angle < 0.0 then
      angle := -angle;
  end;
end;

function triangleArea(i, j, k: integer): real;
begin
  triangleArea := 0.5 * abs((X[j] - X[i]) * (Y[k] - Y[i]) - (X[k] - X[i]) * (Y[j] - Y[i]));
end;

function quadrant(x, y: real): integer;
begin
  if (x > 0.0) and (y >= 0.0) then
    quadrant := 1
  else if (x <= 0.0) and (y > 0.0) then
    quadrant := 2
  else if (x < 0.0) and (y <= 0.0) then
    quadrant := 3
  else
    quadrant := 4;
end;

function distanceToLine(p: integer, i, j: integer): real;
var
  dx, dy, len: real;
begin
  dx := X[j] - X[i];
  dy := Y[j] - Y[i];
  len := sqrt(sqr(dx) + sqr(dy));

  if len < 1.0e-10 then
    distanceToLine := distance(p, i)
  else
    distanceToLine := abs(dy * X[p] - dx * Y[p] + X[i] * Y[p] - Y[i] * X[p]) / len;
end;

function circleRadius(i, j, k: integer): real;
var
  d, ax, ay, bx, by, cx, cy, ux, uy, r: real;
begin
  ax := X[i]; ay := Y[i];
  bx := X[j]; by := Y[j];
  cx := X[k]; cy := Y[k];

  d := 2.0 * (ax * (by - cy) + bx * (cy - ay) + cx * (ay - by));

  if abs(d) < 1.0e-10 then
  begin
    r := distance(i, j);
    r := max(r, distance(j, k));
    r := max(r, distance(i, k));
    circleRadius := r;
    exit;
  end;

  ux := ((sqr(ax) + sqr(ay)) * (by - cy) + (sqr(bx) + sqr(by)) * (cy - ay) + (sqr(cx) + sqr(cy)) * (ay - by)) / d;
  uy := ((sqr(ax) + sqr(ay)) * (cx - bx) + (sqr(bx) + sqr(by)) * (ax - cx) + (sqr(cx) + sqr(cy)) * (bx - ax)) / d;

  r := sqrt(sqr(ax - ux) + sqr(ay - uy));
  circleRadius := r;
end;

procedure LIC1;
var
  i: integer;
begin
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if distance(i, i + 1) > PARAMETERS.LENGTH1 then
    begin
      CMV[1] := true;
      exit;
    end;
  end;
end;

procedure LIC2;
var
  i: integer;
begin
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if circleRadius(i, i + 1, i + 2) > PARAMETERS.RADIUS1 then
    begin
      CMV[2] := true;
      exit;
    end;
  end;
end;

procedure LIC3;
var
  i: integer;
  ang: real;
begin
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    ang := angle(i, i + 1, i + 2);
    if ang < 0.0 then
      continue;

    if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
    begin
      CMV[3] := true;
      exit;
    end;
  end;
end;

procedure LIC4;
var
  i: integer;
begin
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if triangleArea(i, i + 1, i + 2) > PARAMETERS.AREA1 then
    begin
      CMV[4] := true;
      exit;
    end;
  end;
end;

procedure LIC5;
var
  i, j, quad, qcount: integer;
  qset: set of 1..4;
begin
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    qset := [];
    for j := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      quad := quadrant(X[i + j], Y[i + j]);
      qset := qset + [quad];
    end;

    qcount := 0;
    for quad := 1 to 4 do
      if quad in qset then
        inc(qcount);

    if qcount > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      exit;
    end;
  end;
end;

procedure LIC6;
var
  i: integer;
begin
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if X[i + 1] - X[i] < 0.0 then
    begin
      CMV[6] := true;
      exit;
    end;
  end;
end;

procedure LIC7;
var
  i, j: integer;
  maxDist: real;
begin
  CMV[7] := false;
  if NUMPOINTS < 3 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    maxDist := 0.0;
    for j := 0 to PARAMETERS.N_PTS - 1 do
    begin
      maxDist := max(maxDist, distanceToLine(i + j, i, i + PARAMETERS.N_PTS - 1));
    end;

    if maxDist > PARAMETERS.DIST then
    begin
      CMV[7] := true;
      exit;
    end;
  end;
end;

procedure LIC8;
var
  i: integer;
begin
  CMV[8] := false;
  if NUMPOINTS < 3 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    if distance(i, i + PARAMETERS.K_PTS + 1) > PARAMETERS.LENGTH1 then
    begin
      CMV[8] := true;
      exit;
    end;
  end;
end;

procedure LIC9;
var
  i: integer;
begin
  CMV[9] := false;
  if NUMPOINTS < 5 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if circleRadius(i, i + PARAMETERS.A_PTS + 1, i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2) > PARAMETERS.RADIUS1 then
    begin
      CMV[9] := true;
      exit;
    end;
  end;
end;

procedure LIC10;
var
  i: integer;
  ang: real;
begin
  CMV[10] := false;
  if NUMPOINTS < 5 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    ang := angle(i, i + PARAMETERS.C_PTS + 1, i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2);
    if ang < 0.0 then
      continue;

    if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
    begin
      CMV[10] := true;
      exit;
    end;
  end;
end;

procedure LIC11;
var
  i: integer;
begin
  CMV[11] := false;
  if NUMPOINTS < 5 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    if triangleArea(i, i + PARAMETERS.E_PTS + 1, i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2) > PARAMETERS.AREA1 then
    begin
      CMV[11] := true;
      exit;
    end;
  end;
end;

procedure LIC12;
var
  i: integer;
begin
  CMV[12] := false;
  if NUMPOINTS < 3 then
    exit;

  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    if X[i + PARAMETERS.G_PTS + 1] - X[i] < 0.0 then
    begin
      CMV[12] := true;
      exit;
    end;
  end;
end;

procedure LIC13;
var
  i, j: integer;
  part1, part2: boolean;
begin
  CMV[13] := false;
  if NUMPOINTS < 3 then
    exit;

  part1 := false;
  part2 := false;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    if not part1 then
      if distance(i, i + PARAMETERS.K_PTS + 1) > PARAMETERS.LENGTH1 then
        part1 := true;

    if not part2 then
      if distance(i, i + PARAMETERS.K_PTS + 1) < PARAMETERS.LENGTH2 then
        part2 := true;

    if part1 and part2 then
      exit;
  end;

  CMV[13] := part1 and part2;
end;

procedure LIC14;
var
  i: integer;
  part1, part2: boolean;
begin
  CMV[14] := false;
  if NUMPOINTS < 5 then
    exit;

  part1 := false;
  part2 := false;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if not part1 then
      if circleRadius(i, i + PARAMETERS.A_PTS + 1, i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2) > PARAMETERS.RADIUS1 then
        part1 := true;

    if not part2 then
      if circleRadius(i, i + PARAMETERS.A_PTS + 1, i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2) <= PARAMETERS.RADIUS2 then
        part2 := true;

    if part1 and part2 then
      exit;
  end;

  CMV[14] := part1 and part2;
end;

procedure LIC15;
var
  i: integer;
  part1, part2: boolean;
begin
  CMV[15] := false;
  if NUMPOINTS < 5 then
    exit;

  part1 := false;
  part2 := false;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    if not part1 then
      if triangleArea(i, i + PARAMETERS.E_PTS + 1, i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2) > PARAMETERS.AREA1 then
        part1 := true;

    if not part2 then
      if triangleArea(i, i + PARAMETERS.E_PTS + 1, i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2) < PARAMETERS.AREA2 then
        part2 := true;

    if part1 and part2 then
      exit;
  end;

  CMV[15] := part1 and part2;
end;

procedure ComputePUM;
var
  i, j: integer;
begin
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then
        continue;

      case LCM[i, j] of
        NOTUSED:
          PUM[i, j] := true;
        ANDD:
          PUM[i, j] := CMV[i] and CMV[j];
        ORR:
          PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
end;

procedure ComputeFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    allTrue := true;
    for j := 1 to 15 do
    begin
      if j <> i then
      begin
        if not PUM[i, j] then
        begin
          allTrue := false;
          break;
        end;
      end;
    end;

    if (not PUM[i, i]) or allTrue then
      FUV[i] := true
    else
      FUV[i] := false;
  end;
end;

procedure DECIDE;
var
  i: integer;
begin
  CMV[1] := false;
  CMV[2] := false;
  CMV[3] := false;
  CMV[4] := false;
  CMV[5] := false;
  CMV[6] := false;
  CMV[7] := false;
  CMV[8] := false;
  CMV[9] := false;
  CMV[10] := false;
  CMV[11] := false;
  CMV[12] := false;
  CMV[13] := false;
  CMV[14] := false;
  CMV[15] := false;

  LIC1;
  LIC2;
  LIC3;
  LIC4;
  LIC5;
  LIC6;
  LIC7;
  LIC8;
  LIC9;
  LIC10;
  LIC11;
  LIC12;
  LIC13;
  LIC14;
  LIC15;

  ComputePUM;
  ComputeFUV;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
  end;
end;

end.
